"use client";

import { useRef, useCallback } from "react";
import { useFrame, useThree } from "@react-three/fiber";
import type { RapierRigidBody } from "@react-three/rapier";
import * as THREE from "three";
import { useDragStore } from "@/lib/dragStore";

// ── Types ────────────────────────────────────────────────────────────────────

interface DragState {
  /** The Rapier rigid body currently being dragged. */
  body: RapierRigidBody;
  /** World-space position of the body at the start of drag. */
  startPos: { x: number; y: number; z: number };
  /** World-space position of the body in the previous frame (for velocity). */
  prevPos: { x: number; y: number; z: number };
  /** Timestamp of the previous frame (ms, for velocity calc). */
  prevTime: number;
  /** Mouse position (NDC) at pointer-down — used as reference offset. */
  pointerStart: { x: number; y: number };
}

// ── Constants ────────────────────────────────────────────────────────────────

/** Maximum number of position history entries kept for velocity smoothing. */
const HISTORY_SIZE = 3;

// ── Reusable objects (avoid GC in useFrame) ──────────────────────────────────

const _raycaster = new THREE.Raycaster();
const _plane = new THREE.Plane();
const _intersection = new THREE.Vector3();

/**
 * Hook that provides drag event handlers for a Rapier RigidBody.
 *
 * **Pattern (Vercel badge):**
 * 1. `onPointerDown` → switch body to `kinematicPosition`, start tracking
 * 2. `useFrame` → raycast from camera through pointer onto plane at body depth,
 *    call `setNextKinematicTranslation`
 * 3. `onPointerUp` → compute velocity from recent deltas, apply `setLinvel`,
 *    switch back to `dynamic`
 *
 * @param bodyRef — React ref holding the RapierRigidBody (typically from
 *                  `useForwardedRef` or `useRef`)
 * @returns Object with `onPointerDown`, `onPointerUp`, `onPointerOver`,
 *          `onPointerOut` handlers to spread onto a `<mesh>`
 */
export function useDrag(bodyRef: React.RefObject<RapierRigidBody | null>) {
  const { camera, pointer, gl } = useThree();

  // Mutable state that survives across frames without triggering re-renders
  const dragRef = useRef<DragState | null>(null);

  // Position history ring buffer for velocity smoothing
  const historyRef = useRef<
    { pos: THREE.Vector3; time: number }[]
  >([]);
  const historyIndexRef = useRef(0);

  // ── Pointer Down: start dragging ──────────────────────────────────────
  const onPointerDown = useCallback(
    (e: { stopPropagation: () => void }) => {
      const body = bodyRef.current;
      if (!body) return;

      e.stopPropagation();

      // Signal OrbitControls to disable while we drag a bead
      useDragStore.getState().setDragging(true);

      // Switch to kinematic — physics engine won't apply forces to this body
      body.setBodyType({ type: "kinematicPosition" } as never, true);
      body.wakeUp();

      const pos = body.translation();
      const now = performance.now();

      dragRef.current = {
        body,
        startPos: { x: pos.x, y: pos.y, z: pos.z },
        prevPos: { x: pos.x, y: pos.y, z: pos.z },
        prevTime: now,
        pointerStart: { x: pointer.x, y: pointer.y },
      };

      // Reset history
      historyRef.current = [];
      historyIndexRef.current = 0;

      // Change cursor
      gl.domElement.style.cursor = "grabbing";
    },
    [bodyRef, pointer, gl],
  );

  // ── Pointer Up: stop dragging, apply velocity ─────────────────────────
  const onPointerUp = useCallback(() => {
    const drag = dragRef.current;
    if (!drag) return;

    const body = drag.body;
    const history = historyRef.current;

    // Compute average velocity from the last few frames
    if (history.length >= 2) {
      const recent = history.slice(-HISTORY_SIZE);
      const first = recent[0];
      const last = recent[recent.length - 1];
      const dt = (last.time - first.time) / 1000; // seconds

      if (dt > 0.001) {
        const vx = (last.pos.x - first.pos.x) / dt;
        const vy = (last.pos.y - first.pos.y) / dt;
        const vz = (last.pos.z - first.pos.z) / dt;

        // Clamp velocity to prevent crazy throws
        const maxVel = 30;
        const clamp = (v: number) => Math.max(-maxVel, Math.min(maxVel, v));

        body.setLinvel({ x: clamp(vx), y: clamp(vy), z: clamp(vz) }, true);
      }
    }

    // Give a small angular velocity for natural spin feel
    body.setAngvel({ x: 0.5, y: 0, z: 0.2 }, true);

    // Switch back to dynamic
    body.setBodyType({ type: "dynamic" } as never, true);
    body.wakeUp();

    dragRef.current = null;
    historyRef.current = [];
    historyIndexRef.current = 0;

    // Re-enable OrbitControls now that bead drag is finished
    useDragStore.getState().setDragging(false);

    gl.domElement.style.cursor = "auto";
  }, [gl]);

  // ── Cursor handlers ───────────────────────────────────────────────────
  const onPointerOver = useCallback(() => {
    if (!dragRef.current) {
      gl.domElement.style.cursor = "grab";
    }
  }, [gl]);

  const onPointerOut = useCallback(() => {
    if (!dragRef.current) {
      gl.domElement.style.cursor = "auto";
    }
  }, [gl]);

  // ── Per-frame: move kinematic body to follow pointer ──────────────────
  useFrame(() => {
    const drag = dragRef.current;
    if (!drag || !bodyRef.current) return;

    // Construct a plane at the body's current depth, facing the camera
    const bodyPos = drag.body.translation();
    _plane.setFromNormalAndCoplanarPoint(
      camera.getWorldDirection(new THREE.Vector3()).negate(),
      new THREE.Vector3(bodyPos.x, bodyPos.y, bodyPos.z),
    );

    // Raycast from camera through NDC pointer position
    _raycaster.setFromCamera(new THREE.Vector2(pointer.x, pointer.y), camera);

    if (_raycaster.ray.intersectPlane(_plane, _intersection)) {
      const x = _intersection.x;
      const y = _intersection.y;
      const z = _intersection.z;

      drag.body.setNextKinematicTranslation({ x, y, z });

      // Record position for velocity computation
      const now = performance.now();
      const history = historyRef.current;
      history.push({
        pos: new THREE.Vector3(x, y, z),
        time: now,
      });

      // Keep only recent history to bound memory
      if (history.length > HISTORY_SIZE + 1) {
        history.shift();
      }
    }
  });

  return {
    onPointerDown,
    onPointerUp,
    onPointerOver,
    onPointerOut,
    isDragging: dragRef,
  };
}

"use client";

import { Suspense } from "react";
import { Canvas } from "@react-three/fiber";
import { Physics } from "@react-three/rapier";
import {
  OrbitControls,
  Environment,
  ContactShadows,
  Stats,
} from "@react-three/drei";
import { BeadChain } from "./BeadChain";
import AdaptiveRenderer from "./AdaptiveRenderer";
import { useDragStore } from "@/lib/dragStore";
import type { BeadState } from "@/types/bead";

export interface SceneProps {
  /** Array of bead descriptors — drives chain composition. */
  beads: BeadState[];
}

/**
 * OrbitControls wrapper that reads the shared drag flag and disables
 * orbit rotation while a bead is being dragged. This prevents the scene
 * from rotating simultaneously with the bead drag gesture on touch devices.
 *
 * Uses the Zustand hook so React re-renders this component when the flag
 * changes — OrbitControls picks up the new `enabled` prop immediately.
 */
function DragAwareOrbitControls() {
  const isDragging = useDragStore((s) => s.isDragging);
  return (
    <OrbitControls
      makeDefault
      minPolarAngle={0}
      maxPolarAngle={Math.PI}
      minDistance={2}
      maxDistance={20}
      enabled={!isDragging}
    />
  );
}

/**
 * Root 3D scene: Canvas → Physics → BeadChain → ThreadLine.
 * SSR-safe (loaded via SceneLoader with dynamic ssr:false).
 */
export default function Scene({ beads }: SceneProps) {
  return (
    <Canvas
      camera={{ position: [0, 1, 7], fov: 50 }}
      shadows
      style={{ background: "linear-gradient(180deg, #f0f4f8 0%, #d9e2ec 100%)" }}
    >
      {/* Soft gradient background */}
      <color attach="background" args={["#eef2f6"]} />
      <fog attach="fog" args={["#eef2f6", 12, 22]} />

      {/* Lighting: soft studio feel */}
      <ambientLight intensity={0.3} />
      <directionalLight
        position={[5, 8, 5]}
        intensity={1}
        castShadow
        shadow-mapSize-width={1024}
        shadow-mapSize-height={1024}
      />
      {/* Fill light from opposite side for softer shadows */}
      <directionalLight position={[-3, 5, -3]} intensity={0.3} />

      {/* Adaptive rendering — must be inside Canvas for R3F context */}
      <AdaptiveRenderer />

      <Suspense fallback={null}>
        <Environment preset="studio" />

        {/* Physics world: gravity tuned for snappy feel (Vercel pattern) */}
        <Physics gravity={[0, -40, 0]}>
          <BeadChain beads={beads} anchorPosition={[0, 3, 0]} />
        </Physics>

        {/* Soft ground shadow */}
        <ContactShadows
          position={[0, -3, 0]}
          opacity={0.4}
          scale={10}
          blur={2}
          far={4}
        />
      </Suspense>

      <DragAwareOrbitControls />

      {/* FPS overlay — visible in dev only */}
      <Stats />
    </Canvas>
  );
}

"use client";

import dynamic from "next/dynamic";
import { useBeadChain } from "@/hooks/useBeadChain";

// Dynamically import the Scene to avoid SSR issues with Three.js / WebGL
const Scene = dynamic(() => import("@/components/scene/Scene"), {
  ssr: false,
});

/**
 * Client-side wrapper that owns bead chain state and passes it to the Scene.
 * Also renders minimal overlay UI for demo purposes.
 */
export default function SceneLoader() {
  const { beads, addBead, removeLast, reset } = useBeadChain();

  return (
    <div className="relative w-screen h-screen">
      {/* 3D Canvas fills the viewport — touch-action: none prevents
          browser scroll/zoom gestures on touch devices */}
      <div className="canvas-container w-full h-full">
        <Scene beads={beads} />
      </div>

      {/* ── Overlay UI ──────────────────────────────────────────────── */}

      {/* Title */}
      <div className="absolute top-4 left-4 select-none pointer-events-none">
        <h1 className="text-lg font-semibold text-gray-700 tracking-tight">
          Bead Chain
        </h1>
        <p className="text-xs text-gray-400 mt-0.5">
          Drag beads to interact
        </p>
      </div>

      {/* Controls panel */}
      <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex items-center gap-2 rounded-full bg-white/70 backdrop-blur-md shadow-lg px-4 py-2 border border-gray-200/50">
        <span className="text-sm text-gray-500 mr-2">{beads.length} beads</span>

        <button
          onClick={() => addBead()}
          className="px-3 py-1.5 text-sm font-medium rounded-full bg-emerald-50 text-emerald-700 hover:bg-emerald-100 transition-colors cursor-pointer"
        >
          + Add
        </button>

        <button
          onClick={removeLast}
          disabled={beads.length === 0}
          className="px-3 py-1.5 text-sm font-medium rounded-full bg-rose-50 text-rose-700 hover:bg-rose-100 transition-colors disabled:opacity-40 disabled:cursor-not-allowed cursor-pointer"
        >
          − Remove
        </button>

        <button
          onClick={reset}
          className="px-3 py-1.5 text-sm font-medium rounded-full bg-gray-50 text-gray-700 hover:bg-gray-100 transition-colors cursor-pointer"
        >
          ↺ Reset
        </button>
      </div>
    </div>
  );
}

import { create } from "zustand";

interface DragState {
  isDragging: boolean;
  setDragging: (v: boolean) => void;
}

/**
 * Shared drag flag that bridges R3F pointer events (on meshes) and
 * OrbitControls (DOM-level). Set `true` while a bead is being dragged so
 * OrbitControls can disable itself via `enabled={!isDragging}`.
 */
export const useDragStore = create<DragState>((set) => ({
  isDragging: false,
  setDragging: (v) => set({ isDragging: v }),
}));

"use client";

import { AdaptiveDpr, AdaptiveEvents, PerformanceMonitor } from "@react-three/drei";

/**
 * Adaptive rendering controls that live inside <Canvas>.
 *
 * - **AdaptiveDpr**: lowers pixel ratio when FPS drops, raises when stable.
 * - **AdaptiveEvents**: reduces pointer-move resolution on mobile for perf.
 * - **PerformanceMonitor**: watches frame rate and calls incline/decline/fallback
 *   callbacks when the refresh-rate ratio shifts.
 *
 * Bounds use a factor of the display refresh rate:
 *  - lower = 67% of refresh (e.g. 40 FPS at 60 Hz) → triggers decline
 *  - upper = 92% of refresh (e.g. 55 FPS at 60 Hz) → triggers incline
 * This leaves headroom above the 30 FPS minimum target.
 */
export default function AdaptiveRenderer() {
  return (
    <>
      <AdaptiveDpr pixelated />
      <AdaptiveEvents />
      <PerformanceMonitor
        flipflops={5}
        bounds={(refreshRate) => [refreshRate * 0.67, refreshRate * 0.92]}
        onIncline={() => console.log("[perf] FPS improving — increasing quality")}
        onDecline={() => console.log("[perf] FPS dropping — reducing quality")}
        onFallback={() =>
          console.warn("[perf] FPS critically low — fallback applied")
        }
      />
    </>
  );
}

